class Solution:
    def finalPositionOfSnake(self, n: int, commands: List[str]) -> int:
    # Initialize variables
    position = 0
    direction = "RIGHT"
    # Define movement functions
    def move_right():
    nonlocal position
    position += 1
    def move_down():
    nonlocal position
    position += n
    def move_left():
    nonlocal position
    position -= 1
    def move_up():
    nonlocal position
    position -= n
    # Process commands
    for command in commands:
    if command == "RIGHT":
    move_right()
    elif command == "DOWN":
    move_down()
    elif command == "LEFT":
    move_left()
    elif command == "UP":
    move_up()
    # Return final position
    return position

